import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { 
  Search, 
  Filter, 
  Plus, 
  Eye, 
  Edit, 
  AlertTriangle,
  CheckCircle,
  XCircle,
  Clock,
  FileText,
  TrendingUp
} from 'lucide-react';
import qualityService from '../../services/qualityService';
import StatusBadge from '../../components/common/StatusBadge';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';

const QualityControl = () => {
  const [inspections, setInspections] = useState([]);
  const [nonConformities, setNonConformities] = useState([]);
  const [capaActions, setCapaActions] = useState([]);
  const [kpis, setKpis] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('inspections');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedInspection, setSelectedInspection] = useState(null);
  const [showInspectionModal, setShowInspectionModal] = useState(false);
  const [showInspectionForm, setShowInspectionForm] = useState(false);

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    filterData();
  }, [inspections, nonConformities, capaActions, searchTerm, statusFilter]);

  const fetchData = async () => {
    try {
      const [inspectionsData, nonConformitiesData, capaActionsData, kpisData] = await Promise.all([
        qualityService.getQualityInspections(),
        qualityService.getNonConformities(),
        qualityService.getCapaActions(),
        qualityService.getQualityKPIs()
      ]);

      setInspections(inspectionsData);
      setNonConformities(nonConformitiesData);
      setCapaActions(capaActionsData);
      setKpis(kpisData);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching quality data:', error);
      setLoading(false);
    }
  };

  const filterData = () => {
    // La lógica de filtrado se implementaría aquí
    // Por ahora, mostramos todos los datos
  };

  const getInspectionTypeIcon = (type) => {
    switch (type) {
      case 'incoming':
        return <FileText className="w-4 h-4 text-blue-600" />;
      case 'in_process':
        return <Clock className="w-4 h-4 text-yellow-600" />;
      case 'final':
        return <CheckCircle className="w-4 h-4 text-green-600" />;
      case 'customer':
        return <AlertTriangle className="w-4 h-4 text-red-600" />;
      default:
        return <FileText className="w-4 h-4 text-gray-600" />;
    }
  };

  const getSeverityColor = (severity) => {
    switch (severity) {
      case 'critical':
        return 'text-danger-600 bg-danger-100';
      case 'major':
        return 'text-warning-600 bg-warning-100';
      case 'minor':
        return 'text-blue-600 bg-blue-100';
      default:
        return 'text-gray-600 bg-gray-100';
    }
  };

  const handleViewInspection = (inspection) => {
    setSelectedInspection(inspection);
    setShowInspectionModal(true);
  };

  const renderKPIs = () => {
    if (!kpis) return null;

    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Tasa de Aprobación</p>
              <p className="text-2xl font-bold text-success-600">{kpis.quality_pass_rate}%</p>
            </div>
            <TrendingUp className="w-8 h-8 text-success-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">Total Inspecciones</p>
              <p className="text-2xl font-bold text-primary-600">{kpis.total_inspections}</p>
            </div>
            <FileText className="w-8 h-8 text-primary-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">No Conformidades</p>
              <p className="text-2xl font-bold text-danger-600">{kpis.total_non_conformities}</p>
            </div>
            <AlertTriangle className="w-8 h-8 text-danger-500" />
          </div>
        </Card>

        <Card className="p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-secondary-600">CAPA Pendientes</p>
              <p className="text-2xl font-bold text-warning-600">{kpis.pending_capas}</p>
            </div>
            <Clock className="w-8 h-8 text-warning-500" />
          </div>
        </Card>
      </div>
    );
  };

  const renderInspectionsTable = () => (
    <Card>
      <div className="overflow-x-auto">
        <table className="table">
          <thead>
            <tr className="table-header">
              <th className="table-header-cell">Fecha</th>
              <th className="table-header-cell">Tipo</th>
              <th className="table-header-cell">Orden</th>
              <th className="table-header-cell">Cliente</th>
              <th className="table-header-cell">Inspector</th>
              <th className="table-header-cell">Estado</th>
              <th className="table-header-cell">No Conf.</th>
              <th className="table-header-cell">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {inspections.map((inspection) => (
              <tr key={inspection.id} className="table-row">
                <td className="table-cell">
                  {format(new Date(inspection.inspection_date), 'dd/MM/yyyy HH:mm', { locale: es })}
                </td>
                <td className="table-cell">
                  <div className="flex items-center">
                    {getInspectionTypeIcon(inspection.inspection_type)}
                    <span className="ml-2 capitalize">{inspection.inspection_type.replace('_', ' ')}</span>
                  </div>
                </td>
                <td className="table-cell font-medium">{inspection.work_order_number}</td>
                <td className="table-cell">{inspection.customer_name}</td>
                <td className="table-cell">{inspection.inspector_name}</td>
                <td className="table-cell">
                  <StatusBadge status={inspection.status} />
                </td>
                <td className="table-cell">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                    inspection.non_conformities_found > 0 ? 'bg-danger-100 text-danger-800' : 'bg-success-100 text-success-800'
                  }`}>
                    {inspection.non_conformities_found}
                  </span>
                </td>
                <td className="table-cell">
                  <div className="flex space-x-2">
                    <button
                      onClick={() => handleViewInspection(inspection)}
                      className="text-primary-600 hover:text-primary-800"
                      title="Ver detalles"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button
                      className="text-secondary-600 hover:text-secondary-800"
                      title="Editar"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {inspections.length === 0 && (
          <div className="text-center py-8 text-secondary-500">
            No se encontraron inspecciones
          </div>
        )}
      </div>
    </Card>
  );

  const renderNonConformitiesTable = () => (
    <Card>
      <div className="overflow-x-auto">
        <table className="table">
          <thead>
            <tr className="table-header">
              <th className="table-header-cell">Fecha Detección</th>
              <th className="table-header-cell">Tipo</th>
              <th className="table-header-cell">Descripción</th>
              <th className="table-header-cell">Severidad</th>
              <th className="table-header-cell">Orden</th>
              <th className="table-header-cell">Detectado por</th>
              <th className="table-header-cell">Estado</th>
              <th className="table-header-cell">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {nonConformities.map((nc) => (
              <tr key={nc.id} className="table-row">
                <td className="table-cell">
                  {format(new Date(nc.detection_date), 'dd/MM/yyyy HH:mm', { locale: es })}
                </td>
                <td className="table-cell">
                  <span className="capitalize">{nc.type.replace('_', ' ')}</span>
                </td>
                <td className="table-cell">
                  <div className="max-w-xs truncate" title={nc.description}>
                    {nc.description}
                  </div>
                </td>
                <td className="table-cell">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${getSeverityColor(nc.severity)}`}>
                    {nc.severity}
                  </span>
                </td>
                <td className="table-cell font-medium">{nc.work_order_number}</td>
                <td className="table-cell">{nc.detected_by_name}</td>
                <td className="table-cell">
                  <StatusBadge status={nc.status} />
                </td>
                <td className="table-cell">
                  <div className="flex space-x-2">
                    <button
                      className="text-primary-600 hover:text-primary-800"
                      title="Ver detalles"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button
                      className="text-secondary-600 hover:text-secondary-800"
                      title="Editar"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {nonConformities.length === 0 && (
          <div className="text-center py-8 text-secondary-500">
            No se encontraron no conformidades
          </div>
        )}
      </div>
    </Card>
  );

  const renderCAPATable = () => (
    <Card>
      <div className="overflow-x-auto">
        <table className="table">
          <thead>
            <tr className="table-header">
              <th className="table-header-cell">Título</th>
              <th className="table-header-cell">Tipo</th>
              <th className="table-header-cell">Asignado a</th>
              <th className="table-header-cell">Fecha Límite</th>
              <th className="table-header-cell">Estado</th>
              <th className="table-header-cell">Efectividad</th>
              <th className="table-header-cell">Acciones</th>
            </tr>
          </thead>
          <tbody>
            {capaActions.map((capa) => (
              <tr key={capa.id} className="table-row">
                <td className="table-cell font-medium">{capa.title}</td>
                <td className="table-cell">
                  <span className="capitalize">{capa.type}</span>
                </td>
                <td className="table-cell">{capa.assigned_to_name}</td>
                <td className="table-cell">
                  {capa.due_date 
                    ? format(new Date(capa.due_date), 'dd/MM/yyyy', { locale: es })
                    : '-'
                  }
                </td>
                <td className="table-cell">
                  <StatusBadge status={capa.status} />
                </td>
                <td className="table-cell">
                  {capa.effectiveness_rating ? (
                    <div className="flex items-center">
                      <div className="flex">
                        {[...Array(5)].map((_, i) => (
                          <span
                            key={i}
                            className={`text-sm ${
                              i < capa.effectiveness_rating ? 'text-yellow-400' : 'text-gray-300'
                            }`}
                          >
                            ★
                          </span>
                        ))}
                      </div>
                      <span className="ml-2 text-sm text-secondary-600">
                        ({capa.effectiveness_rating}/5)
                      </span>
                    </div>
                  ) : (
                    '-'
                  )}
                </td>
                <td className="table-cell">
                  <div className="flex space-x-2">
                    <button
                      className="text-primary-600 hover:text-primary-800"
                      title="Ver detalles"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button
                      className="text-secondary-600 hover:text-secondary-800"
                      title="Editar"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {capaActions.length === 0 && (
          <div className="text-center py-8 text-secondary-500">
            No se encontraron acciones CAPA
          </div>
        )}
      </div>
    </Card>
  );

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-secondary-900">Control de Calidad</h1>
          <p className="text-secondary-600">Gestión de inspecciones, no conformidades y acciones CAPA</p>
        </div>
        <Button
          onClick={() => setShowInspectionForm(true)}
          className="btn-primary"
        >
          <Plus className="w-4 h-4 mr-2" />
          Nueva Inspección
        </Button>
      </div>

      {/* KPIs */}
      {renderKPIs()}

      {/* Filters */}
      <Card>
        <div className="p-4">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-secondary-400 w-4 h-4" />
                <Input
                  placeholder="Buscar inspecciones, no conformidades..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
            <div className="w-full sm:w-48">
              <select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                className="input"
              >
                <option value="">Todos los estados</option>
                <option value="pending">Pendiente</option>
                <option value="approved">Aprobado</option>
                <option value="rejected">Rechazado</option>
                <option value="rework">Rework</option>
              </select>
            </div>
          </div>
        </div>
      </Card>

      {/* Tabs */}
      <div className="border-b border-secondary-200">
        <nav className="-mb-px flex space-x-8">
          {[
            { id: 'inspections', label: 'Inspecciones', count: inspections.length },
            { id: 'non-conformities', label: 'No Conformidades', count: nonConformities.length },
            { id: 'capa', label: 'Acciones CAPA', count: capaActions.length }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`py-2 px-1 border-b-2 font-medium text-sm ${
                activeTab === tab.id
                  ? 'border-primary-500 text-primary-600'
                  : 'border-transparent text-secondary-500 hover:text-secondary-700 hover:border-secondary-300'
              }`}
            >
              {tab.label}
              {tab.count > 0 && (
                <span className="ml-2 bg-secondary-100 text-secondary-600 py-0.5 px-2 rounded-full text-xs">
                  {tab.count}
                </span>
              )}
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      {activeTab === 'inspections' && renderInspectionsTable()}
      {activeTab === 'non-conformities' && renderNonConformitiesTable()}
      {activeTab === 'capa' && renderCAPATable()}

      {/* Inspection Details Modal */}
      <Modal
        isOpen={showInspectionModal}
        onClose={() => setShowInspectionModal(false)}
        title={`Detalles de Inspección - ${selectedInspection?.work_order_number}`}
        size="lg"
      >
        {selectedInspection && (
          <div className="space-y-6">
            {/* Inspection Information */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-secondary-700 mb-1">
                  Tipo de Inspección
                </label>
                <div className="flex items-center">
                  {getInspectionTypeIcon(selectedInspection.inspection_type)}
                  <span className="ml-2 capitalize">{selectedInspection.inspection_type.replace('_', ' ')}</span>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-secondary-700 mb-1">
                  Estado
                </label>
                <StatusBadge status={selectedInspection.status} />
              </div>
              <div>
                <label className="block text-sm font-medium text-secondary-700 mb-1">
                  Inspector
                </label>
                <p className="text-secondary-900">{selectedInspection.inspector_name}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-secondary-700 mb-1">
                  Fecha de Inspección
                </label>
                <p className="text-secondary-900">
                  {format(new Date(selectedInspection.inspection_date), 'dd/MM/yyyy HH:mm', { locale: es })}
                </p>
              </div>
            </div>

            {/* Results */}
            {selectedInspection.results && (
              <div>
                <h3 className="font-semibold text-secondary-900 mb-3">Resultados de Inspección</h3>
                <div className="bg-secondary-50 rounded-lg p-4">
                  <pre className="text-sm text-secondary-700 whitespace-pre-wrap">
                    {JSON.stringify(selectedInspection.results, null, 2)}
                  </pre>
                </div>
              </div>
            )}

            {/* Notes */}
            {selectedInspection.notes && (
              <div>
                <label className="block text-sm font-medium text-secondary-700 mb-1">
                  Notas
                </label>
                <p className="text-secondary-900 bg-secondary-50 rounded-lg p-3">
                  {selectedInspection.notes}
                </p>
              </div>
            )}

            {/* Actions */}
            <div className="flex justify-end space-x-3">
              <Button
                onClick={() => setShowInspectionModal(false)}
                className="btn-secondary"
              >
                Cerrar
              </Button>
              {selectedInspection.status === 'pending' && (
                <Button className="btn-success">
                  Aprobar Inspección
                </Button>
              )}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default QualityControl;
